from datetime import date

def compute_overdue_alerts(registry: list[ImpactEntry]) -> list[dict]:
    """Identify overdue items and compute escalation level."""
    today = date.today()
    alerts = []
    for entry in registry:
        if entry.status in (Status.closed, Status.accepted):
            continue
        days_overdue = (today - entry.due_date).days
        if days_overdue <= 0:
            continue
        level = "owner"
        if days_overdue > 30:
            level = "executive"
        elif days_overdue > 7:
            level = "manager"
        alerts.append({
            "impact_id": entry.impact_id,
            "owner": entry.owner,
            "days_overdue": days_overdue,
            "severity": entry.severity.value,
            "escalation_level": level,
        })
    return sorted(alerts, key=lambda x: x["days_overdue"], reverse=True)

# Run daily in your CI/CD pipeline or monitoring cron
alerts = compute_overdue_alerts(registry)
for alert in alerts:
    print(f"[{alert['escalation_level'].upper()}] {alert['impact_id']} "
          f"({alert['severity']}) overdue {alert['days_overdue']}d — {alert['owner']}")
